def solve(*args):
    if not args:
        return None

    # Assuming args is a list of integers representing levels
    levels = list(args)

    # Validate inputs vs contract
    if any(not isinstance(level, int) or level < 1 for level in levels):
        raise ValueError("All levels must be positive integers starting from 1.")

    # Implement core logic
    results = []
    for level in levels:
        if level == 1:
            results.append("Level 1: Basic Challenge")
        elif level == 2:
            results.append("Level 2: Intermediate Challenge")
        elif level == 3:
            results.append("Level 3: Advanced Challenge")
        elif level == 4:
            results.append("Level 4: Expert Challenge")
        else:
            results.append(f"Level {level}: Unknown Challenge")

    return results
